from __future__ import annotations

from dataclasses import dataclass
from typing import Any
import shutil
from uuid import uuid4

from fusion_gate.backup import backup_sqlite
from fusion_gate.executor import GeminiExecutionError, GeminiExecutor
from fusion_gate.repository import RunRepository
from fusion_gate.schemas import RunRequest


class ModuleError(RuntimeError):
    def __init__(self, code: str, message: str):
        super().__init__(message)
        self.code = code
        self.message = message


@dataclass
class ModuleContext:
    repo: RunRepository
    executor: GeminiExecutor
    settings: Any


@dataclass
class ModuleDefinition:
    name: str
    description: str
    safe_remote: bool
    uses_gemini: bool
    schema: dict[str, Any]

    def run(self, req: RunRequest, ctx: ModuleContext) -> dict[str, Any]:
        raise NotImplementedError


class SimpleGeminiModule(ModuleDefinition):
    def run(self, req: RunRequest, ctx: ModuleContext) -> dict[str, Any]:
        expect_json = self.name == "format_json"
        prompt = build_prompt(self.name, req)
        result = ctx.executor.run(prompt=prompt, expect_json=expect_json, timeout_seconds=_timeout_for(self.name))
        if expect_json:
            return {
                "result": {
                    "type": "json",
                    "json": result.payload,
                },
                "artifacts": [],
                "retries": 0,
                "fallback_used": False,
                "tokens_in_est": result.tokens_in_est,
                "tokens_out_est": result.tokens_out_est,
                "cost_est_usd": result.cost_est_usd,
            }
        return {
            "result": {
                "type": "text",
                "text": result.text,
            },
            "artifacts": [],
            "retries": 0,
            "fallback_used": False,
            "tokens_in_est": result.tokens_in_est,
            "tokens_out_est": result.tokens_out_est,
            "cost_est_usd": result.cost_est_usd,
        }


class CompareModule(ModuleDefinition):
    def run(self, req: RunRequest, ctx: ModuleContext) -> dict[str, Any]:
        if len(req.payload.items) < 2:
            raise ModuleError("VALIDATION_ERROR", "compare requires at least two payload.items")

        retries = 0
        fallback_used = False
        left, right = req.payload.items[0], req.payload.items[1]
        try:
            left_summary = ctx.executor.run(
                prompt=f"Summarize item A:\n{left}",
                expect_json=False,
                timeout_seconds=30,
            )
            right_summary = ctx.executor.run(
                prompt=f"Summarize item B:\n{right}",
                expect_json=False,
                timeout_seconds=30,
            )
            final = ctx.executor.run(
                prompt=(
                    "Compare these two summarized inputs.\n"
                    f"A: {left_summary.text}\n"
                    f"B: {right_summary.text}\n"
                    "Return a concise comparison."
                ),
                expect_json=False,
                timeout_seconds=60,
            )
        except GeminiExecutionError:
            retries = 1
            fallback_used = True
            final = ctx.executor.run(
                prompt=f"Compare these inputs directly.\nA: {left}\nB: {right}",
                expect_json=False,
                timeout_seconds=60,
            )

        return {
            "result": {
                "type": "text",
                "text": final.text,
            },
            "artifacts": [],
            "retries": retries,
            "fallback_used": fallback_used,
            "tokens_in_est": final.tokens_in_est,
            "tokens_out_est": final.tokens_out_est,
            "cost_est_usd": final.cost_est_usd,
        }


class OpsHealthModule(ModuleDefinition):
    def run(self, req: RunRequest, ctx: ModuleContext) -> dict[str, Any]:
        return {
            "result": {
                "type": "json",
                "json": {
                    "db_ok": ctx.repo.ping(),
                    "gemini_bin_found": shutil.which(ctx.settings.gemini_bin) is not None,
                    "mock_gemini": ctx.settings.mock_gemini,
                    "logs_dir": str(ctx.settings.logs_dir),
                },
            },
            "artifacts": [],
            "retries": 0,
            "fallback_used": False,
            "tokens_in_est": 0,
            "tokens_out_est": 0,
            "cost_est_usd": 0.0,
        }


class OpsStatusModule(ModuleDefinition):
    def run(self, req: RunRequest, ctx: ModuleContext) -> dict[str, Any]:
        total_runs = ctx.repo.count_runs()
        failed_runs = ctx.repo.count_failures()
        failure_rate = (failed_runs / total_runs) if total_runs else 0.0
        return {
            "result": {
                "type": "json",
                "json": {
                    "total_runs": total_runs,
                    "failed_runs": failed_runs,
                    "failure_rate": failure_rate,
                    "database_url": ctx.settings.database_url,
                    "modules": sorted(REGISTRY.keys()),
                },
            },
            "artifacts": [],
            "retries": 0,
            "fallback_used": False,
            "tokens_in_est": 0,
            "tokens_out_est": 0,
            "cost_est_usd": 0.0,
        }


